-- ── PART 3: Update cv_url untuk kandidat dari seed 06 & 07 ──
-- (menggunakan real Google Drive ID format sebagai placeholder)
UPDATE candidate_skills cs
SET cv_url = CONCAT('https://drive.google.com/open?id=',
    SUBSTR(MD5(r.nama || r.posisi || r.id::TEXT), 1, 28))
FROM recruitment r
WHERE cs.recruitment_id = r.id
  AND cs.cv_url IS NULL;

-- ── PART 4: 500 candidate_skills tambahan untuk recruitment seed 07 ──
-- Insert skills bagi kandidat seed07 yang belum punya skills (40% dari 500)

-- Mengisi candidate_skills yang kosong dari seed 07 secara batch
-- Query ini menemukan recruitment tanpa skills dan mengisinya
INSERT INTO candidate_skills
  (recruitment_id, pendidikan, jurusan, pengalaman_thn, pengalaman_desc, skills, catatan_hr, cv_url)
SELECT
  r.id,
  CASE
    WHEN r.posisi IN ('Finance Manager','HRD Manager','Marketing Manager','Operational Manager',
                      'Manager Operasional','Internal Audit','Business Development Executive')
         THEN CASE (r.id % 3) WHEN 0 THEN 'S2' WHEN 1 THEN 'S1' ELSE 'S1' END
    WHEN r.posisi IN ('Staff Accounting','Staff HRD','Staff General Affair','Staff Purchasing',
                      'Staff QC','Social Media Specialist','Training and Development Officer',
                      'Design Graphic','Content Creator','Marketing Executive','Sales Executive',
                      'Supervisor Store Batas Kota','Supervisor Store Tambua',
                      'Supervisor Store/Pelayanan','Supervisor Produksi',
                      'Supervisor Supply Chain & Production Control',
                      'Supervisor Supply Chain Management','Admin Operasional')
         THEN CASE (r.id % 3) WHEN 0 THEN 'S1' WHEN 1 THEN 'D3' ELSE 'S1' END
    WHEN r.posisi IN ('Teknisi','Staff Produksi','Captain Store','Captain Frontliner',
                      'Captain Store Bantimurung','Captain Store Batas Kota','Captain Store Tambua')
         THEN CASE (r.id % 3) WHEN 0 THEN 'SMK' WHEN 1 THEN 'SMA' ELSE 'SMK' END
    ELSE 'SMA'
  END AS pendidikan,
  CASE (r.id % 5)
    WHEN 0 THEN 'Manajemen'
    WHEN 1 THEN 'Akuntansi'
    WHEN 2 THEN 'Ilmu Komunikasi'
    WHEN 3 THEN 'Tata Niaga'
    ELSE 'Administrasi Bisnis'
  END AS jurusan,
  CASE
    WHEN r.posisi LIKE '%Manager%' OR r.posisi LIKE '%Manager%' THEN (r.id % 8) + 3
    WHEN r.posisi LIKE '%Supervisor%' OR r.posisi LIKE '%Captain%' THEN (r.id % 5) + 2
    ELSE (r.id % 4)
  END AS pengalaman_thn,
  CASE (r.id % 6)
    WHEN 0 THEN 'Pernah bekerja di bidang yang relevan sebelumnya.'
    WHEN 1 THEN 'Fresh graduate dengan pengalaman magang 3-6 bulan.'
    WHEN 2 THEN 'Berpengalaman di posisi sejenis selama beberapa tahun.'
    WHEN 3 THEN 'Baru lulus, belum pernah bekerja formal.'
    WHEN 4 THEN 'Memiliki pengalaman di industri yang berkaitan.'
    ELSE 'Pernah bekerja part-time di bidang terkait.'
  END AS pengalaman_desc,
  CASE r.posisi
    WHEN 'Staff Frontliner'
      THEN '[{"skill":"Komunikasi","level":' || (5 + r.id%4)::TEXT || '},{"skill":"Pelayanan Pelanggan","level":' || (5 + r.id%3)::TEXT || '},{"skill":"Kasir / POS System","level":' || (4 + r.id%4)::TEXT || '}]'
    WHEN 'Staff Produksi'
      THEN '[{"skill":"Ketelitian","level":' || (5 + r.id%4)::TEXT || '},{"skill":"Fisik Prima","level":' || (6 + r.id%3)::TEXT || '},{"skill":"Kerja Tim","level":' || (5 + r.id%4)::TEXT || '}]'
    WHEN 'Staff QC'
      THEN '[{"skill":"Quality Control","level":' || (5 + r.id%4)::TEXT || '},{"skill":"Ketelitian","level":' || (6 + r.id%3)::TEXT || '},{"skill":"Dokumentasi QC","level":' || (4 + r.id%4)::TEXT || '}]'
    WHEN 'Driver'
      THEN '[{"skill":"Mengemudi","level":' || (7 + r.id%3)::TEXT || '},{"skill":"Navigasi Daerah Maros","level":' || (6 + r.id%4)::TEXT || '},{"skill":"Disiplin","level":' || (7 + r.id%3)::TEXT || '}]'
    WHEN 'Design Graphic'
      THEN '[{"skill":"Adobe Photoshop","level":' || (5 + r.id%4)::TEXT || '},{"skill":"Canva","level":' || (6 + r.id%4)::TEXT || '},{"skill":"Konten Sosial Media","level":' || (5 + r.id%3)::TEXT || '}]'
    WHEN 'Content Creator'
      THEN '[{"skill":"Video Editing","level":' || (5 + r.id%4)::TEXT || '},{"skill":"Copywriting","level":' || (5 + r.id%3)::TEXT || '},{"skill":"Instagram / TikTok","level":' || (6 + r.id%4)::TEXT || '}]'
    ELSE
      '[{"skill":"Komunikasi","level":' || (5 + r.id%3)::TEXT || '},{"skill":"Kerja Tim","level":' || (5 + r.id%4)::TEXT || '},{"skill":"Microsoft Excel","level":' || (4 + r.id%4)::TEXT || '}]'
  END::JSONB AS skills,
  CASE (r.id % 8)
    WHEN 0 THEN 'Kandidat potensial, attitude baik dan komunikatif.'
    WHEN 1 THEN 'Pengalaman relevan sesuai posisi. Direkomendasikan.'
    WHEN 2 THEN 'Perlu verifikasi lanjutan. Skill masih perlu diasah.'
    WHEN 3 THEN 'Fresh graduate tapi antusias. Butuh training.'
    WHEN 4 THEN 'Domisili dalam Maros. Bisa langsung produktif.'
    WHEN 5 THEN 'Ekspektasi gaji sesuai range budget perusahaan.'
    WHEN 6 THEN 'Pengisian form lengkap. Menunjukkan keseriusan melamar.'
    ELSE 'Perlu konfirmasi lebih lanjut sebelum keputusan.'
  END AS catatan_hr,
  CONCAT('https://drive.google.com/open?id=', SUBSTR(MD5(r.nama || r.id::TEXT), 1, 28)) AS cv_url
FROM recruitment r
LEFT JOIN candidate_skills cs ON cs.recruitment_id = r.id
WHERE cs.id IS NULL
  AND r.screening_cv IS NOT NULL
LIMIT 500;
